SELECT c.*, CASE WHEN c.begin_date > c.end_date THEN '已结课' WHEN c.begin_date < c.end_date THEN '未开班' ELSE '在读中' END AS status, e.name AS masterName FROM clazz c LEFT JOIN emp e ON c.master_id = e.id
AND c.name LIKE CONCAT('%', #{name}, '%')
AND c.create_time BETWEEN #{begin} AND #{end}
